///   rotation: Vector3.zero(), // No rotation (for 2D)
/// );
/// ```
class FractalViewState {
  /// The 2D pan offset from the fractal center.
  ///
  /// For 2D fractals, this determines which part of the complex plane
  /// is visible. Positive X moves right, positive Y moves down.
  ///
  /// Typical range: -3.0 to 3.0 for each axis.
  final Vector2 pan;

  /// The current zoom/magnification level.
  ///
  /// - Values > 1.0 zoom in (magnify)
  /// - Values < 1.0 zoom out (shrink)
  /// - Value of 1.0 is the default view
  ///
  /// In controller updates, this is typically clamped to [1e-9, 1e12]
  /// to allow deep-zoom workflows.
  final double zoom;

  /// The 3D rotation angles in radians.
  ///
  /// For 3D fractals like Mandelbulb, this controls the camera orientation:
  /// - x: Rotation around the X axis (pitch)
  /// - y: Rotation around the Y axis (yaw)
  /// - z: Rotation around the Z axis (roll)
  ///
  /// For 2D fractals, this is typically [Vector3.zero()].
  final Vector3 rotation;

  /// Creates a [FractalViewState] with specific view parameters.
  ///
  /// All parameters are required to define a complete view state.
  const FractalViewState({
    required this.pan,
    required this.zoom,
    required this.rotation,
  });

  /// Creates the initial/default view state.
  ///
  /// Centers the view with no pan offset, 1x zoom, and no rotation.
  /// This is the starting point when a fractal is first loaded.
  FractalViewState.initial()
      : pan = Vector2.zero(),
        zoom = 1.0,
        rotation = Vector3.zero();

  /// Creates a copy of this view state with the given fields replaced.
  ///
  /// Unspecified fields retain their original values.
  ///
  /// Example:
  /// ```dart
  /// final zoomed = view.copyWith(zoom: view.zoom * 2);
  /// ```
  FractalViewState copyWith({
    Vector2? pan,
    double? zoom,
    Vector3? rotation,
  }) {
    return FractalViewState(
      pan: pan ?? this.pan,
      zoom: zoom ?? this.zoom,
      rotation: rotation ?? this.rotation,
    );
  }
}

import 'dart:math' as math;
import 'dart:ui';

/// Replayable geometry for the 2D fractal minimap.
///
/// The widget paints a tiny overview and an indicator for the currently visible
/// renderer viewport. Keeping the coordinate math pure lets tests characterize
/// assumptions about zoom samples, minimap size, and renderer aspect ratio
/// without relying on a canvas paint pass.
final class MiniMapGeometry {
  static const double defaultZoom = 1.0;
  static const double minimumIndicatorDimension = 4.0;

  /// Fractal-plane span represented by the minimap overview on each axis.
  static const double overviewWorldSpan = 4.0;

  const MiniMapGeometry._();

  static double normalizeZoom(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return defaultZoom;
    return zoom;
  }

  static Offset normalizePan(Offset pan) {
    return Offset(
      pan.dx.isFinite ? pan.dx : 0.0,
      pan.dy.isFinite ? pan.dy : 0.0,
    );
  }

  /// Maps an absolute fractal-plane pan center to minimap pixels.
  static Offset centerForPan({
    required Offset pan,
    required Size minimapSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    final safePan = normalizePan(pan);
    return Offset(
      width / 2.0 + safePan.dx * width / overviewWorldSpan,
      height / 2.0 + safePan.dy * height / overviewWorldSpan,
    );
  }

  /// Inverse of [centerForPan] for tap-to-pan jumps.
  static Offset panForCenter({
    required Offset center,
    required Size minimapSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    final safeCenter = Offset(
      center.dx.isFinite ? center.dx : width / 2.0,
      center.dy.isFinite ? center.dy : height / 2.0,
    );
    return Offset(
      (safeCenter.dx / width - 0.5) * overviewWorldSpan,
      (safeCenter.dy / height - 0.5) * overviewWorldSpan,
    );
  }

  static Rect viewportRect({
    required Offset pan,
    required double zoom,
    required Size minimapSize,
    required Size viewportSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Rect.zero;

    final safePan = normalizePan(pan);
    final safeZoom = normalizeZoom(zoom);
    final safeViewportSize = _positiveFiniteViewportSize(viewportSize);
    final viewportShortSide = math.min(
      safeViewportSize.width,
      safeViewportSize.height,
    );
    final viewportWidthScale = safeViewportSize.width / viewportShortSide;
    final viewportHeightScale = safeViewportSize.height / viewportShortSide;

    final baseViewportWidth = (2.0 / safeZoom) * (width / overviewWorldSpan);
    final baseViewportHeight = (2.0 / safeZoom) * (height / overviewWorldSpan);
    final center = centerForPan(pan: safePan, minimapSize: minimapSize);

    return Rect.fromCenter(
      center: center,
      width: _clampIndicatorDimension(
        baseViewportWidth * viewportWidthScale,
        width,
      ),
      height: _clampIndicatorDimension(
        baseViewportHeight * viewportHeightScale,
        height,
      ),
    );
  }

  static Offset panForTap({
    required Offset localPosition,
    required Size minimapSize,
    required double zoom,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    // Pan is an absolute fractal-plane center; zoom changes the viewport
    // indicator size, not which overview coordinate a tap selects.
    return panForCenter(center: localPosition, minimapSize: minimapSize);
  }

  static double _positiveFiniteOrZero(double value) {
    return value.isFinite && value > 0.0 ? value : 0.0;
  }

  static Size _positiveFiniteViewportSize(Size size) {
    if (_positiveFiniteOrZero(size.width) == 0.0 ||
        _positiveFiniteOrZero(size.height) == 0.0) {
      return const Size(1, 1);
    }
    return size;
  }

  static double _clampIndicatorDimension(double value, double extent) {
    final lower = math.min(minimumIndicatorDimension, extent);
    if (!value.isFinite || value <= 0.0) return lower;
    return value.clamp(lower, extent).toDouble();
  }
}

import 'dart:ui';

import 'package:flutter_fractals/features/minimap/geometry/minimap_geometry.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('MiniMapGeometry.viewportRect', () {
    test('preserves the rendered viewport aspect ratio', () {
      final rect = MiniMapGeometry.viewportRect(
        pan: Offset.zero,
        zoom: 2.0,
        minimapSize: const Size(240, 240),
        viewportSize: const Size(1600, 900),
      );

      expect(rect.center, const Offset(120, 120));
      expect(rect.width / rect.height, closeTo(16 / 9, 1e-9));
    });

    test('keeps square viewport dimensions compatible with legacy mapping', () {
      final rect = MiniMapGeometry.viewportRect(
        pan: const Offset(1, -1),
        zoom: 2.0,
        minimapSize: const Size(120, 120),
        viewportSize: const Size(600, 600),
      );

      expect(rect.center, const Offset(90, 30));
      expect(rect.width, 30);
      expect(rect.height, 30);
    });

    test('normalizes malformed zoom samples instead of producing NaN rects',
        () {
      final rect = MiniMapGeometry.viewportRect(
        pan: const Offset(double.nan, double.infinity),
        zoom: double.nan,
        minimapSize: const Size(120, 120),
        viewportSize: Size.zero,
      );

      expect(rect.center, const Offset(60, 60));
      expect(rect.width, 60);
      expect(rect.height, 60);
    });
  });

  group('MiniMapGeometry.panForTap', () {
    test('is the inverse of viewport center mapping', () {
      const minimapSize = Size(120, 120);
      const viewportSize = Size(600, 600);
      const tap = Offset(120, 0);

      for (final zoom in [0.5, 1.0, 2.0, 8.0]) {
        final pan = MiniMapGeometry.panForTap(
          localPosition: tap,
          minimapSize: minimapSize,
          zoom: zoom,
        );
        final rect = MiniMapGeometry.viewportRect(
          pan: pan,
          zoom: zoom,
          minimapSize: minimapSize,
          viewportSize: viewportSize,
        );

        expect(rect.center.dx, closeTo(tap.dx, 1e-9), reason: 'zoom=$zoom');
        expect(rect.center.dy, closeTo(tap.dy, 1e-9), reason: 'zoom=$zoom');
      }
    });

    test('maps taps to absolute minimap coordinates independent of zoom', () {
      final zoomedOut = MiniMapGeometry.panForTap(
        localPosition: const Offset(120, 0),
        minimapSize: const Size(120, 120),
        zoom: 0.5,
      );
      final zoomedIn = MiniMapGeometry.panForTap(
        localPosition: const Offset(120, 0),
        minimapSize: const Size(120, 120),
        zoom: 8.0,
      );

      expect(zoomedOut, const Offset(2.0, -2.0));
      expect(zoomedIn, zoomedOut);
    });
  });
}

import 'package:flutter_fractals/core/models/export_options.dart';

const int defaultCustomExportWidth = 1920;
const int defaultCustomExportHeight = 1080;

int resolveCustomExportDimension({
  required String fieldText,
  required int? currentValue,
  required int fallback,
}) {
  final parsed = int.tryParse(fieldText.trim());
  if (parsed != null && parsed > 0) return parsed;
  if (currentValue != null && currentValue > 0) return currentValue;
  return fallback;
}

ExportOptions withResolvedCustomExportDimensions({
  required ExportOptions options,
  required String widthText,
  required String heightText,
}) {
  return options.copyWith(
    customWidth: resolveCustomExportDimension(
      fieldText: widthText,
      currentValue: options.customWidth,
      fallback: defaultCustomExportWidth,
    ),
    customHeight: resolveCustomExportDimension(
      fieldText: heightText,
      currentValue: options.customHeight,
      fallback: defaultCustomExportHeight,
    ),
  );
}

